#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char destination[101];
        char season[101];
        int companions, duration;
        scanf("%s %s", destination, season);
        scanf("%d %d", &companions, &duration);
        printf("You are planning a trip to %s during %s.\n", destination, season);
        printf("You will be traveling with %d companions for %d days.\n", companions, duration);
    }
    return 0;
}

