code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String[] first = br.readLine().trim().split(" ");
            String destination = first[0];
            String season = first[1];
            String[] second = br.readLine().trim().split(" ");
            int companions = Integer.parseInt(second[0]);
            int duration = Integer.parseInt(second[1]);
            sb.append("You are planning a trip to ").append(destination).append(" during ").append(season).append('.').append('\n');
            sb.append("You will be traveling with ").append(companions).append(" companions for ").append(duration).append(" days.").append('\n');
        }
        System.out.print(sb.toString());
    }
}

