let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx].trim(), 10);
idx++;
let out = [];
for (let t = 0; t < T; t++) {
  const [destination, season] = input[idx].trim().split(/\s+/);
  idx++;
  const [companionsStr, durationStr] = input[idx].trim().split(/\s+/);
