  const companions = parseInt(companionsStr, 10);
  const duration = parseInt(durationStr, 10);
  out.push(`You are planning a trip to ${destination} during ${season}.`);
  out.push(`You will be traveling with ${companions} companions for ${duration} days.`);
}
